import{_ as n,o as a,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const u=JSON.parse('{"title":"分布式架构","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/index.md","filePath":"distributed/index.md","lastUpdated":1774318215000}'),i={name:"distributed/index.md"};function l(r,s,t,c,o,d){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="分布式架构" tabindex="-1">分布式架构 <a class="header-anchor" href="#分布式架构" aria-label="Permalink to “分布式架构”">​</a></h1><p>分布式系统有三盏灯，但只能亮两盏。</p><p>这就是 CAP 理论告诉我们的：一致性（Consistency）、可用性（Availability）、分区容错性（Partition Tolerance），你最多只能同时满足两个。</p><p>等等，分区容错性怎么能不选呢？</p><p>简单来说：<strong>网络分区是必然的</strong>。你的服务器可能跨机房、跨地域，光纤可能被挖断，路由器可能抽风。在分布式系统中，P 不是可选项，是必选项。</p><p>所以，<strong>CAP 理论本质上是在问：C 和 A，你选哪个？</strong></p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>分布式架构是现代后端系统的基石。从微服务拆分到分布式事务，从一致性理论到工程落地，每一个环节都有无数细节值得深究。</p><p>|| 方向 | 篇数 | 核心目标 | ||------|------|----------| || <a href="/distributed/theory/index">分布式理论</a> | 25 篇 | CAP/BASE、一致性、共识算法、分布式协调 | || <a href="/distributed/transaction/index">分布式事务</a> | 13 篇 | Seata AT/TCC/SAGA、可靠消息、XA 规范 | || <a href="/distributed/lock/index">分布式锁</a> | 12 篇 | Redis/ZooKeeper/etcd 分布式锁实现 | || <a href="/distributed/zookeeper/index">分布式协调服务</a> | 16 篇 | ZooKeeper、etcd、Nacos 注册中心与配置中心 | || <a href="/distributed/governance/index">服务治理</a> | 11 篇 | 熔断、降级、限流、负载均衡、幂等 | || <a href="/distributed/dubbo/index">服务调用</a> | 16 篇 | Dubbo、Feign、gRPC 原理与实践 | || <a href="/distributed/scenario/index">典型场景方案</a> | 33 篇 | 多级缓存、分布式 Session、文件存储、多机房部署 |</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><p>分布式架构的知识点很多，建议按照这个顺序学习：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：理论奠基（1-2 周）</span></span>
<span class="line"><span>→ 分布式理论：CAP、BASE、一致性模型</span></span>
<span class="line"><span>→ 分布式协调：2PC、3PC、Paxos、Raft</span></span>
<span class="line"><span>→ 这个阶段重在理解，不需要死记硬背</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：核心组件（2-3 周）</span></span>
<span class="line"><span>→ 分布式锁：Redis 分布式锁、Redisson、ZooKeeper 锁</span></span>
<span class="line"><span>→ 分布式事务：AT、TCC、SAGA、可靠消息</span></span>
<span class="line"><span>→ 分布式协调服务：ZooKeeper、etcd、Nacos</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：服务治理（1-2 周）</span></span>
<span class="line"><span>→ 熔断、降级、限流、超时、重试</span></span>
<span class="line"><span>→ 服务发现与负载均衡</span></span>
<span class="line"><span>→ 幂等性设计</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：工程实践（持续）</span></span>
<span class="line"><span>→ 多级缓存架构</span></span>
<span class="line"><span>→ 分布式 Session 与 SSO</span></span>
<span class="line"><span>→ 多机房部署与数据同步</span></span>
<span class="line"><span>→ 全链路追踪与监控</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>分布式架构的面试考察，本质上是看你对「分布式系统复杂性」的理解程度：</p><ol><li><strong>理论理解</strong>：能不能讲清楚 CAP、BASE、一致性模型的取舍</li><li><strong>原理深度</strong>：能不能讲清楚 Raft/Paxos 的核心流程和工程难点</li><li><strong>方案选型</strong>：能不能根据业务场景选择合适的方案（而不是背答案）</li><li><strong>问题排查</strong>：能不能分析生产环境中的实际问题（如缓存一致性、锁竞争）</li></ol><p>好的回答不在于「我知道」，而在于「我能讲清楚为什么」。</p><blockquote><p>&quot;分布式系统的本质，是在不确定性中寻找确定性。用协议代替信任，用幂等代替重试，用降级代替崩溃。&quot;</p></blockquote>`,17)])])}const h=n(i,[["render",l]]);export{u as __pageData,h as default};
